585. // updateCreate routes input to the create form, re-deriving the profile menu
586. // when the chosen directory's repository changes, and forwards the command that
587. // carries the form's decision back to the top-level Update.
588. func (m Model) updateCreate(msg tea.Msg) (tea.Model, tea.Cmd) {
589. 	prevBranchRepo := m.form.BranchRepo
590. 	var cmd tea.Cmd
591. 	m.form, cmd = m.form.Update(msg)
592. 	if m.form.BranchRepo != prevBranchRepo {
593. 		m.form.SetProfiles(m.profilesFor(m.form.BranchRepo))
594. 	}
595. 	return m, cmd
596. }
