666. // addWorkspace registers the git repository at path as a workspace and makes it
667. // the active tab, resetting the cursor to the top of its (likely empty) session
668. // list. It routes through the same repo.Resolve + repo.Register path the CLI and
669. // auto-registration use, so the workspace lands under the same content-addressed
670. // id: picking an already-registered repository activates its existing tab rather
671. // than duplicating it, and reg is persisted only when a workspace was newly
672. // created. A directory that is not yet a git repository is not rejected outright:
673. // it routes to a confirm that offers to git-init it first, so a new or
674. // not-yet-versioned project can be turned into a workspace without dropping to a
675. // shell.
676. func (m Model) addWorkspace(path string) (tea.Model, tea.Cmd) {
677. 	repoPath, remoteURL, err := repo.Resolve(path)
678. 	if err != nil {
679. 		return m.confirmInitWorkspace(path)
680. 	}
681. 	m.mode = modeList
682. 	ws, created := repo.Register(m.reg, repoPath, remoteURL)
683. 	if created {
684. 		if err := m.reg.Save(); err != nil {
685. 			m.err = err
686. 			return m, m.afterListChange()
687. 		}
688. 		m.status = "added workspace " + ws.Name
689. 	} else {
690. 		m.status = "workspace " + ws.Name + " already added"
691. 	}
692. 	m.err = nil
693. 	m.activeID = ws.ID
694. 	m.cursor = 0
695. 	return m, m.refresh()
696. }
