698. // confirmInitWorkspace opens a confirm dialog offering to git-init the directory
699. // at path before registering it as a workspace, reached when path is not yet a git
700. // repository. It guards that path is an existing directory first: a non-directory
701. // (or a path that has gone away) is surfaced as an error rather than offered an
702. // init that could not make sense, so only a real folder is ever proposed for
703. // initialization. Confirming runs initWorkspaceCmd; cancelling returns to the list
704. // untouched.
705. func (m Model) confirmInitWorkspace(path string) (tea.Model, tea.Cmd) {
706. 	info, statErr := os.Stat(path)
707. 	if statErr != nil || !info.IsDir() {
708. 		m.mode = modeList
709. 		m.err = fmt.Errorf("%s is not a git repository", path)
710. 		return m, m.afterListChange()
711. 	}
712. 	body := fmt.Sprintf(
713. 		"%s is not a git repository.\n\n", component.HomeRel(path, m.osHome),
714. 	) +
715. 		"Initialize a git repository here and add it as a workspace? " +
716. 		"This creates a .git directory in that folder; nothing else on disk " +
717. 		"is touched."
718. 	return m.enterConfirm(
719. 		modal.NewConfirmDialog(
720. 			m.theme,
721. 			"Initialize repository",
722. 			body,
723. 			"Initialize",
724. 			"Cancel",
725. 			false,
726. 		),
727. 		m.initWorkspaceCmd(path),
728. 	)
729. }
