731. // initWorkspaceCmd git-inits the directory at path and registers it as a
732. // workspace, returning a workspaceAddedMsg with the outcome. It runs off the
733. // update loop because it shells out to git; the model is mutated when the message
734. // lands. reg is persisted only when a new workspace was created, mirroring
735. // addWorkspace.
736. func (m Model) initWorkspaceCmd(path string) tea.Cmd {
737. 	reg := m.reg
738. 	return func() tea.Msg {
