756. // enterWorkspaceDelete opens the delete-confirmation modal for the active
757. // workspace. Deleting a workspace cascades: every session it owns is torn down —
758. // tmux stopped, worktree removed, branch and any uncommitted work discarded —
759. // before the workspace tab is removed, so the confirm spells out how many
760. // sessions go and that the work on their branches is gone. The repository on disk
761. // is never touched. With no active workspace it is a no-op.
762. func (m Model) enterWorkspaceDelete() (tea.Model, tea.Cmd) {
763. 	ws := m.currentWorkspace()
