777. // workspaceDeleteWarning is the confirm-body line describing what deleting a
778. // workspace with n sessions does, made specific so the user sees the blast radius
779. // before confirming.
780. func workspaceDeleteWarning(n int) string {
781. 	switch n {
782. 	case 0:
783. 		return "It has no sessions. The repository on disk is not touched."
784. 	case 1:
