786. 			"discarding the branch and any uncommitted work on it. " +
787. 			"The repository on disk is not touched."
788. 	default:
789. 		return fmt.Sprintf(
790. 			"This tears down all %d sessions — removing their worktrees and "+
791. 				"discarding their branches and any uncommitted work on them. "+
792. 				"The repository on disk is not touched.", n,
793. 		)
794. 	}
