797. // workspaceDeleteCmd tears down ws and removes its tab. It captures ws's
798. // companion shell names up front so the bulk teardown can kill them too — they
799. // are a cockpit artifact the shared launch.DeleteWorkspace path does not know
800. // about — then runs the cascade, kills the companions, and persists reg.
801. func (m Model) workspaceDeleteCmd(ws *registry.Workspace) tea.Cmd {
802. 	reg, home, be := m.reg, m.home, m.tmux
803. 	var companions []string
804. 	for _, s := range m.workspaceSessions() {
805. 		companions = append(companions, companionName(s.TmuxName))
806. 	}
807. 	name := ws.Name
808. 	return func() tea.Msg {
809. 		if _, err := launch.DeleteWorkspace(reg, be, home, ws); err != nil {
810. 			return workspaceDeletedMsg{err: err}
811. 		}
812. 		for _, c := range companions {
813. 			_ = be.Kill(c)
814. 		}
815. 		if err := reg.Save(); err != nil {
