822. // toggleRecording flips repo-level recording for the active workspace, off the
823. // update loop. It is a no-op on the orphan tab (no workspace). The command reads
824. // the current state fresh (record.InstalledAgents) rather than trusting the
825. // cached m.recording map, so a concurrent CLI change can't make the toggle act
826. // on stale state, and routes both directions through the same record package the
827. // `wasa record` command uses.
828. func (m Model) toggleRecording() (tea.Model, tea.Cmd) {
829. 	ws := m.currentWorkspace()
830. 	if ws == nil {
831. 		return m, nil
832. 	}
833. 	dir, name := ws.RepoPath, ws.Name
834. 	return m, func() tea.Msg {
835. 		if len(record.InstalledAgents(dir)) > 0 {
836. 			if err := record.RemoveHooks(dir); err != nil {
837. 				return recordToggledMsg{wsName: name, err: err}
838. 			}
839. 			return recordToggledMsg{wsName: name, enabled: false}
840. 		}
841. 		agents, err := record.Enable(dir)
842. 		if err != nil {
843. 			return recordToggledMsg{wsName: name, err: err}
844. 		}
845. 		if len(agents) == 0 {
846. 			return recordToggledMsg{wsName: name, none: true}
847. 		}
848. 		return recordToggledMsg{wsName: name, enabled: true, agents: agents}
849. 	}
