855. // directory inside an already-registered repository offers that workspace's
856. // profiles; one inside an unregistered repository offers the single default
857. // profile a fresh workspace would be created with, so the selection stays valid
858. // for the workspace the worktree lands in.
859. func (m Model) profilesFor(branchRepo string) []string {
860. 	if branchRepo == "" {
