888. // validProfile constrains a chosen profile name to ws: it returns name when ws
889. // has a profile by that name, and otherwise "" so the workspace default is used
890. // rather than sending an unknown name that SelectProfile would reject.
891. func validProfile(ws *registry.Workspace, name string) string {
