218. // subLine renders a row's detail line — the branch ref, an optional coloured
219. // +N/−M churn token, then the profile and status — padded to w. The churn token
220. // carries its own add/remove colours, so the line is composed from segments each
221. // rendered with descS rather than one descS.Render over the whole string:
222. // embedding the token's colour reset inside a single Render would cut the
223. // selection band short for everything after it on the selected row. When the
224. // churn token would not fit, the plain line is rendered instead so a row never
225. // overflows its column.
226. func (m Model) subLine(
227. 	s *registry.Session,
228. 	ref string,
229. 	rs sessionstatus.Status,
230. 	descS lipgloss.Style,
231. 	selected bool,
232. 	w int,
233. ) string {
234. 	plain := fmt.Sprintf(
235. 		"   %s %s · %s · %s", branchIcon, ref, s.ProfileName, rs.Label(),
236. 	)
237. 	churn := m.churnToken(s, selected)
238. 	rec := m.recordedToken(s, selected)
239. 	if churn == "" && rec == "" {
240. 		return descS.Render(component.PadAnsi(plain, w))
241. 	}
242. 
243. 	pre := fmt.Sprintf("   %s %s ", branchIcon, ref)
244. 	post := fmt.Sprintf(" · %s · %s", s.ProfileName, rs.Label())
245. 	base := ansi.StringWidth(pre) + ansi.StringWidth(churn) +
246. 		ansi.StringWidth(post)
247. 	if base > w {
248. 		return descS.Render(component.PadAnsi(plain, w))
249. 	}
250. 
251. 	sep := " · "
252. 	used, recSeg := base, ""
253. 	if rec != "" {
254. 		add := ansi.StringWidth(sep) + ansi.StringWidth(rec)
255. 		if base+add <= w {
256. 			recSeg, used = descS.Render(sep)+rec, base+add
257. 		}
258. 	}
259. 
260. 	line := descS.Render(pre) + churn + descS.Render(post) + recSeg
261. 	if tail := w - used; tail > 0 {
262. 		line += descS.Render(strings.Repeat(" ", tail))
263. 	}
264. 	return line
265. }
