267. // churnToken renders a worktree session's +N/−M churn in the diff add/remove
268. // colours, or "" when there is nothing to show: a plain session, a session whose
269. // churn has not been computed yet, or a clean worktree (zero churn renders no
270. // +0/−0 noise). On the selected row the add/remove styles inherit the selection
271. // band's background so the coloured digits sit on the band rather than punching a
272. // hole in it.
273. func (m Model) churnToken(s *registry.Session, selected bool) string {
274. 	if s.Branch == "" || s.WorktreePath == "" || s.BaseCommit == "" {
275. 		return ""
276. 	}
277. 	c, ok := m.churn[s.ID]
278. 	if !ok || (c.added == 0 && c.removed == 0) {
279. 		return ""
280. 	}
281. 	add, del := m.theme.DiffAddStyle, m.theme.DiffDelStyle
282. 	if selected {
283. 		bg := m.theme.SelRowDescStyle.GetBackground()
284. 		add, del = add.Background(bg), del.Background(bg)
285. 	}
286. 	return add.Render(fmt.Sprintf("+%d", c.added)) + "/" +
287. 		del.Render(fmt.Sprintf("−%d", c.removed))
