 // sessions pane.
 func (m Model) tabbedRightPane(contentW, bodyH int) string {
 	s := m.selectedSession()
 	running := s != nil && s.Status == registry.StatusRunning
 	return m.tabbed.Body(
 		m.theme, contentW, bodyH, running, m.diffSession(s), m.termSession(s),
 	)
