 			return r.node
 		}
 	}
 	return nil
 }

 // childNames is the names of n's loaded children, in order.
 func childNames(n *treeNode) []string {
 	out := make([]string, len(n.children))
 	for i, c := range n.children {
 		out[i] = c.name
 	}
 	return out
